// ─────────────────────────────────────────────
// Build morning briefing per group, with personality
// ─────────────────────────────────────────────
const norm = (v) => String(v||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');

const groupsResp = $('Fetch Active Groups').item.json;
const groupsList = Array.isArray(groupsResp) ? groupsResp : (groupsResp?.data || []);

// Fallback se a tabela jarvis_groups não estiver populada
const FALLBACK_GROUPS = [
  { wa_chat_id: '120363426390515923@g.us', label: 'Angel Fly', context_key: 'angelfly' },
  { wa_chat_id: '120363420996892188@g.us', label: 'Garlic N Lemons', context_key: 'garlic' },
  { wa_chat_id: '120363422948599063@g.us', label: 'Ernesto', context_key: 'ernesto' }
];
const groups = groupsList.length ? groupsList : FALLBACK_GROUPS;

const collect = (items) => {
  const all = [];
  for (const it of items) {
    const j = it.json;
    if (Array.isArray(j)) j.forEach(r => r?.id && all.push(r));
    else if (Array.isArray(j?.data)) j.data.forEach(r => r?.id && all.push(r));
    else if (j?.id) all.push(j);
  }
  return all;
};
const tasks   = collect($('Fetch All Tasks').all());
const tickets = collect($('Fetch All Tickets').all());

const now = new Date();
const brt = new Date(now.getTime() - 3*3600000);
const today = brt.toISOString().slice(0,10);
const yesterday = new Date(brt.getTime() - 24*3600000).toISOString().slice(0,10);

const isOpen = (s) => !['done','closed','cancelled','resolved','completed'].includes(norm(s));
const dateOf = (o) => (o?.deadline || o?.due_date || o?.created_date || o?.created_at || '').slice(0,10);
const groupMatch = (o, ctx) => {
  const blob = norm(o?.project_name||'') + ' ' + norm(o?.client_name||'');
  if (ctx==='garlic')   return /garlic|gnl/.test(blob);
  if (ctx==='ernesto')  return /ernesto/.test(blob);
  if (ctx==='angelfly') return /angel\s*fly|cockpit/.test(blob);
  return true;
};

const fmt = (x, field='title') => {
  const name = x[field] || x.title || x.subject || '(sem título)';
  const a = x.assigned_to_name ? ' 👤 ' + x.assigned_to_name : '';
  const d = (x.deadline || x.due_date) ? ' 📅 ' + (x.deadline||x.due_date).slice(0,10) : '';
  const p = x.priority && x.priority !== 'medium' ? ' [' + x.priority.toUpperCase() + ']' : '';
  return '• ' + name + p + a + d;
};

const greetings = [
  '☀️ *Bom dia, equipe {LABEL}!*\nCafé tomado, Cockpit aberto, bora ver o que cai hoje.',
  '🌅 *Bom dia, {LABEL}!*\nMais um dia, mais um deploy. Segue o que temos:',
  '☕ *Bom dia, {LABEL}!*\nLevantando a poeira do backlog. Olha só:',
  '🚀 *E aí, equipe {LABEL}!*\nAcordando os atrasos e separando as prioridades. Vai assim:',
  '🔆 *Salve, {LABEL}!*\nResumo matinal saindo do forno. Agenda do dia:'
];
const pickGreeting = (label) => greetings[Math.floor(Math.random()*greetings.length)].replace('{LABEL}', label);

const closings = [
  '\nBora! 💪',
  '\nManda ver! 🚀',
  '\nQue o dia seja produtivo. ✨',
  '\nVamos com fé. 🔥',
  '\nDay 1 mode ON. 👊'
];
const pickClosing = () => closings[Math.floor(Math.random()*closings.length)];

const results = [];
for (const g of groups) {
  const ctx = g.context_key || g.context;
  const label = g.label || ctx;
  const chatId = g.wa_chat_id;

  const gOpen   = tasks.filter(t => isOpen(t.status) && groupMatch(t, ctx));
  const gToday  = gOpen.filter(t => dateOf(t) === today);
  const overdue = gOpen.filter(t => t.deadline && t.deadline.slice(0,10) < today);

  const gOpenTk  = tickets.filter(t => isOpen(t.status) && groupMatch(t, ctx));
  const gNewTk   = gOpenTk.filter(t => dateOf(t) === yesterday || dateOf(t) === today);

  let msg = pickGreeting(label) + '\n';

  if (overdue.length) {
    msg += '\n🚨 *Atrasadas (' + overdue.length + ')* — eh, olha aí:\n';
    msg += overdue.slice(0,5).map(t => fmt(t)).join('\n');
    if (overdue.length > 5) msg += '\n_… e mais ' + (overdue.length-5) + '_';
  }

  if (gToday.length) {
    msg += '\n\n📋 *Hoje (' + gToday.length + '):*\n';
    msg += gToday.map(t => fmt(t)).join('\n');
  }

  if (gNewTk.length) {
    msg += '\n\n🎫 *Tickets recentes (' + gNewTk.length + '):*\n';
    msg += gNewTk.slice(0,5).map(t => fmt(t,'subject')).join('\n');
  }

  if (!gToday.length && !overdue.length && !gNewTk.length) {
    msg += '\n\n✨ Nada urgente nem pra hoje. Aproveita pra atacar o backlog ou tirar um café estendido.';
  }

  msg += '\n\n📊 *Status geral:* ' + gOpen.length + ' tasks abertas · ' + gOpenTk.length + ' tickets abertos';
  msg += pickClosing();

  results.push({ json: { number: chatId, text: msg, label } });
}

return results;
